import 'package:flutter_test/flutter_test.dart';\nimport 'package:chefmind_ai_app/features/recipes/domain/entities/recipe.dart';\nimport 'package:chefmind_ai_app/features/recipes/domain/entities/recipe_ingredient.dart';\nimport 'package:chefmind_ai_app/features/recipes/domain/entities/instruction.dart';\nimport 'package:chefmind_ai_app/features/recipes/domain/entities/ingredient.dart';\n\nvoid main() {\n  group('Recipe Entity Tests', () {\n    late Recipe testRecipe;\n    late List<RecipeIngredient> testIngredients;\n    late List<Instruction> testInstructions;\n\n    setUp(() {\n      testIngredients = [\n        const RecipeIngredient(\n          ingredientId: 'ing1',\n          name: 'Flour',\n          quantity: 2.0,\n          unit: 'cups',\n          category: 'grains',\n        ),\n        const RecipeIngredient(\n          ingredientId: 'ing2',\n          name: 'Sugar',\n          quantity: 1.0,\n          unit: 'cup',\n          category: 'sweeteners',\n        ),\n      ];\n\n      testInstructions = [\n        const Instruction(\n          id: 'inst1',\n          stepNumber: 1,\n          description: 'Mix flour and sugar in a large bowl',\n          type: InstructionType.mixing,\n        ),\n        const Instruction(\n          id: 'inst2',\n          stepNumber: 2,\n          description: 'Add wet ingredients and mix until combined',\n          type: InstructionType.mixing,\n          duration: Duration(minutes: 5),\n        ),\n      ];\n\n      testRecipe = Recipe(\n        id: 'recipe1',\n        title: 'Simple Cake',\n        description: 'A delicious and easy cake recipe',\n        authorId: 'user1',\n        authorName: 'Chef John',\n        ingredients: testIngredients,\n        instructions: testInstructions,\n        servings: 8,\n        prepTime: const Duration(minutes: 15),\n        cookTime: const Duration(minutes: 30),\n        totalTime: const Duration(minutes: 45),\n        difficulty: RecipeDifficulty.easy,\n        cuisineTypes: ['american'],\n        mealTypes: ['dessert'],\n        tags: ['cake', 'dessert', 'easy'],\n        createdAt: DateTime.now(),\n      );\n    });\n\n    test('should create recipe with required fields', () {\n      expect(testRecipe.id, 'recipe1');\n      expect(testRecipe.title, 'Simple Cake');\n      expect(testRecipe.description, 'A delicious and easy cake recipe');\n      expect(testRecipe.authorId, 'user1');\n      expect(testRecipe.servings, 8);\n      expect(testRecipe.ingredients.length, 2);\n      expect(testRecipe.instructions.length, 2);\n    });\n\n    test('should have correct default values', () {\n      const minimalRecipe = Recipe(\n        id: 'recipe2',\n        title: 'Minimal Recipe',\n        description: 'Basic recipe',\n        authorId: 'user2',\n        servings: 1,\n      );\n\n      expect(minimalRecipe.imageUrls, isEmpty);\n      expect(minimalRecipe.ingredients, isEmpty);\n      expect(minimalRecipe.instructions, isEmpty);\n      expect(minimalRecipe.rating, 0.0);\n      expect(minimalRecipe.reviewCount, 0);\n      expect(minimalRecipe.favoriteCount, 0);\n      expect(minimalRecipe.viewCount, 0);\n      expect(minimalRecipe.difficulty, RecipeDifficulty.medium);\n      expect(minimalRecipe.status, RecipeStatus.draft);\n      expect(minimalRecipe.visibility, RecipeVisibility.public);\n      expect(minimalRecipe.isVerified, false);\n      expect(minimalRecipe.isFeatured, false);\n      expect(minimalRecipe.isOriginal, false);\n    });\n\n    test('should serialize to and from JSON correctly', () {\n      final json = testRecipe.toJson();\n      final deserializedRecipe = Recipe.fromJson(json);\n\n      expect(deserializedRecipe.id, testRecipe.id);\n      expect(deserializedRecipe.title, testRecipe.title);\n      expect(deserializedRecipe.description, testRecipe.description);\n      expect(deserializedRecipe.authorId, testRecipe.authorId);\n      expect(deserializedRecipe.servings, testRecipe.servings);\n      expect(deserializedRecipe.ingredients.length, testRecipe.ingredients.length);\n      expect(deserializedRecipe.instructions.length, testRecipe.instructions.length);\n      expect(deserializedRecipe.difficulty, testRecipe.difficulty);\n    });\n\n    test('should handle copyWith correctly', () {\n      final updatedRecipe = testRecipe.copyWith(\n        title: 'Updated Cake',\n        servings: 12,\n        difficulty: RecipeDifficulty.medium,\n      );\n\n      expect(updatedRecipe.title, 'Updated Cake');\n      expect(updatedRecipe.servings, 12);\n      expect(updatedRecipe.difficulty, RecipeDifficulty.medium);\n      // Other fields should remain the same\n      expect(updatedRecipe.id, testRecipe.id);\n      expect(updatedRecipe.description, testRecipe.description);\n      expect(updatedRecipe.authorId, testRecipe.authorId);\n    });\n\n    test('should handle time calculations correctly', () {\n      expect(testRecipe.prepTime?.inMinutes, 15);\n      expect(testRecipe.cookTime?.inMinutes, 30);\n      expect(testRecipe.totalTime?.inMinutes, 45);\n    });\n\n    test('should handle nutrition summary correctly', () {\n      final nutritionSummary = NutritionSummary(\n        caloriesPerServing: 250.0,\n        proteinPerServing: 5.0,\n        carbsPerServing: 45.0,\n        fatPerServing: 8.0,\n        fiberPerServing: 2.0,\n        healthScore: NutritionScore.good,\n        isLowCalorie: true,\n        isHighProtein: false,\n      );\n\n      final recipeWithNutrition = testRecipe.copyWith(nutrition: nutritionSummary);\n\n      expect(recipeWithNutrition.nutrition?.caloriesPerServing, 250.0);\n      expect(recipeWithNutrition.nutrition?.healthScore, NutritionScore.good);\n      expect(recipeWithNutrition.nutrition?.isLowCalorie, true);\n      expect(recipeWithNutrition.nutrition?.isHighProtein, false);\n    });\n\n    test('should handle recipe variations correctly', () {\n      final variation = RecipeVariation(\n        id: 'var1',\n        name: 'Gluten-Free Version',\n        description: 'Made with gluten-free flour',\n        substitutions: [\n          const IngredientSubstitution(\n            originalIngredientId: 'ing1',\n            substituteIngredientId: 'ing3',\n            substituteName: 'Gluten-Free Flour',\n            reason: SubstitutionReason.dietary,\n          ),\n        ],\n        additionalTags: ['gluten-free'],\n      );\n\n      final recipeWithVariation = testRecipe.copyWith(variations: [variation]);\n\n      expect(recipeWithVariation.variations.length, 1);\n      expect(recipeWithVariation.variations.first.name, 'Gluten-Free Version');\n      expect(recipeWithVariation.variations.first.substitutions.length, 1);\n      expect(recipeWithVariation.variations.first.additionalTags, contains('gluten-free'));\n    });\n\n    test('should handle cost estimate correctly', () {\n      final costEstimate = CostEstimate(\n        totalCost: 12.50,\n        costPerServing: 1.56,\n        currency: 'USD',\n        costLevel: CostLevel.low,\n        ingredientCosts: [\n          const IngredientCost(\n            ingredientId: 'ing1',\n            ingredientName: 'Flour',\n            cost: 3.00,\n            costPerUnit: 1.50,\n            unit: 'cup',\n            quantity: 2.0,\n          ),\n        ],\n      );\n\n      final recipeWithCost = testRecipe.copyWith(costEstimate: costEstimate);\n\n      expect(recipeWithCost.costEstimate?.totalCost, 12.50);\n      expect(recipeWithCost.costEstimate?.costPerServing, 1.56);\n      expect(recipeWithCost.costEstimate?.costLevel, CostLevel.low);\n      expect(recipeWithCost.costEstimate?.ingredientCosts.length, 1);\n    });\n\n    test('should handle recipe notes correctly', () {\n      final note = RecipeNote(\n        id: 'note1',\n        content: 'This recipe works great with vanilla extract',\n        authorId: 'user1',\n        authorName: 'Chef John',\n        type: NoteType.tip,\n        isPublic: true,\n        createdAt: DateTime.now(),\n      );\n\n      final recipeWithNotes = testRecipe.copyWith(notes: [note]);\n\n      expect(recipeWithNotes.notes.length, 1);\n      expect(recipeWithNotes.notes.first.content, 'This recipe works great with vanilla extract');\n      expect(recipeWithNotes.notes.first.type, NoteType.tip);\n      expect(recipeWithNotes.notes.first.isPublic, true);\n    });\n\n    test('should handle seasonal information correctly', () {\n      const seasonalInfo = SeasonalInfo(\n        bestSeasons: [Season.fall, Season.winter],\n        seasonalIngredients: ['apples', 'cinnamon'],\n        holidayAssociations: ['Thanksgiving', 'Christmas'],\n        seasonalNotes: 'Perfect for autumn celebrations',\n      );\n\n      final recipeWithSeasonal = testRecipe.copyWith(seasonalInfo: seasonalInfo);\n\n      expect(recipeWithSeasonal.seasonalInfo?.bestSeasons, contains(Season.fall));\n      expect(recipeWithSeasonal.seasonalInfo?.seasonalIngredients, contains('apples'));\n      expect(recipeWithSeasonal.seasonalInfo?.holidayAssociations, contains('Thanksgiving'));\n    });\n  });\n\n  group('Recipe Enums Tests', () {\n    test('RecipeDifficulty enum should have correct values', () {\n      expect(RecipeDifficulty.values.length, 5);\n      expect(RecipeDifficulty.values, contains(RecipeDifficulty.beginner));\n      expect(RecipeDifficulty.values, contains(RecipeDifficulty.expert));\n    });\n\n    test('RecipeStatus enum should have correct values', () {\n      expect(RecipeStatus.values.length, 5);\n      expect(RecipeStatus.values, contains(RecipeStatus.draft));\n      expect(RecipeStatus.values, contains(RecipeStatus.published));\n    });\n\n    test('CuisineType enum should have comprehensive values', () {\n      expect(CuisineType.values.length, greaterThan(15));\n      expect(CuisineType.values, contains(CuisineType.italian));\n      expect(CuisineType.values, contains(CuisineType.chinese));\n      expect(CuisineType.values, contains(CuisineType.fusion));\n    });\n\n    test('MealType enum should cover all meal categories', () {\n      expect(MealType.values, contains(MealType.breakfast));\n      expect(MealType.values, contains(MealType.lunch));\n      expect(MealType.values, contains(MealType.dinner));\n      expect(MealType.values, contains(MealType.dessert));\n      expect(MealType.values, contains(MealType.snack));\n    });\n\n    test('DietaryRestriction enum should cover common restrictions', () {\n      expect(DietaryRestriction.values, contains(DietaryRestriction.vegetarian));\n      expect(DietaryRestriction.values, contains(DietaryRestriction.vegan));\n      expect(DietaryRestriction.values, contains(DietaryRestriction.glutenFree));\n      expect(DietaryRestriction.values, contains(DietaryRestriction.keto));\n      expect(DietaryRestriction.values, contains(DietaryRestriction.paleo));\n    });\n  });\n\n  group('NutritionSummary Tests', () {\n    test('should create nutrition summary with default values', () {\n      const nutrition = NutritionSummary();\n\n      expect(nutrition.caloriesPerServing, 0.0);\n      expect(nutrition.proteinPerServing, 0.0);\n      expect(nutrition.carbsPerServing, 0.0);\n      expect(nutrition.fatPerServing, 0.0);\n      expect(nutrition.healthScore, NutritionScore.unknown);\n      expect(nutrition.isLowCalorie, false);\n      expect(nutrition.isHighProtein, false);\n    });\n\n    test('should serialize nutrition summary correctly', () {\n      const nutrition = NutritionSummary(\n        caloriesPerServing: 300.0,\n        proteinPerServing: 15.0,\n        carbsPerServing: 40.0,\n        fatPerServing: 10.0,\n        healthScore: NutritionScore.good,\n        isLowCalorie: true,\n      );\n\n      final json = nutrition.toJson();\n      final deserialized = NutritionSummary.fromJson(json);\n\n      expect(deserialized.caloriesPerServing, 300.0);\n      expect(deserialized.proteinPerServing, 15.0);\n      expect(deserialized.healthScore, NutritionScore.good);\n      expect(deserialized.isLowCalorie, true);\n    });\n  });\n}\n